css_template:
.ticker-vert-container {
    position: absolute;
    bottom: 0;
    left: 0;
    width: var(--v-width, 100%);
    min-height: var(--v-height, 60px);
    display: flex;
    align-items: stretch;
    background: {{PRIMARY_BG}};
    border: {{BORDER_WIDTH}}px solid {{BORDER_COLOR}};
    border-radius: {{BORDER_RADIUS}}px;
    font-family: '{{FONT_FAMILY}}', sans-serif;
    box-shadow: {{BOX_SHADOW}};
    opacity: 0;
    transform: translateY(100px);
    overflow: hidden;
    box-sizing: border-box;
}
.ticker-vert-label {
    position: relative;
    background: {{WIPER_BG}};
    padding: 0 40px;
    display: flex;
    align-items: center;
    justify-content: center;
    flex-shrink: 0;
    box-shadow: 5px 0 15px rgba(0,0,0,0.5);
    z-index: 2;
    overflow: hidden;
}
{{#unless INTRO_TEXT}} .ticker-vert-label { display: none !important; } {{/unless}}
.ticker-vert-label::before {
    content: '';
    position: absolute;
    top: 0;
    left: -100%;
    width: 60%;
    height: 100%;
    display: {{#if WIPER_GLEAM_ENABLED}}block{{else}}none{{/if}};
    background: {{WIPER_GLEAM_BG}};
    transform: skewX(-20deg);
    pointer-events: none;
    animation: sweep-gleam-v8 {{WIPER_GLEAM_DURATION}}s infinite ease-in-out;
}
.wiper-text-v8 {
    font-weight: {{WIPER_FONT_WEIGHT}};
    font-size: {{WIPER_FONT_SIZE}}px;
    font-family: {{WIPER_FONT}}, sans-serif;
    color: {{WIPER_TEXT_COLOR}};
    letter-spacing: {{WIPER_LETTER_SPACING}}px;
    position: relative;
    z-index: 1;
    white-space: nowrap;
}
.ticker-vert-viewport {
    flex: 1;
    position: relative;
    overflow: hidden;
}
.ticker-vert-item {
    position: absolute;
    width: 100%;
    padding: 0 20px;
    height: 100%;
    display: flex;
    align-items: center;
    color: {{TITLE_COLOR}};
    font-size: {{TITLE_SIZE}}px;
    font-weight: {{TITLE_WEIGHT}};
    text-transform: {{TITLE_TRANSFORM}};
    white-space: nowrap;
    opacity: 0;
    transform: translateY(100%);
    box-sizing: border-box;
}
.ticker-vert-item.entering {
    animation: ticker-vert-in 0.5s ease-out forwards;
}
.ticker-vert-item.leaving {
    animation: ticker-vert-out 0.5s ease-in forwards;
}
@keyframes ticker-vert-in {
    from { transform: translateY(100%); opacity: 0; }
    to { transform: translateY(0); opacity: 1; }
}
@keyframes ticker-vert-out {
    from { transform: translateY(0); opacity: 1; }
    to { transform: translateY(-100%); opacity: 0; }
}
@keyframes sweep-gleam-v8 {
    0% { left: -100%; }
    100% { left: 200%; }
}

js_template:
(() => {
    const root = document.getElementById("{{ID}}");
    const container = root.querySelector('.ticker-vert-container');
    const viewport = root.querySelector('.ticker-vert-viewport');
    const dataEl = root.querySelector('.ticker-vert-data');
    if (!container || !viewport || !dataEl) return;

    let items = [];
    try { items = JSON.parse(dataEl.textContent || '[]'); } catch(e) { items = ['BRAK DANYCH']; }
    if (!items.length) items = ['BRAK WIADOMOŚCI'];

    let currentIndex = 0;
    let cycleRunning = false;
    let cycleTimer = null;
    const displayMs = Math.max(1000, (parseFloat("{{TICKER_SPEED}}") || 5) * 1000);

    function adjustFontSize(el) {
        const baseFontSizeStr = "{{TITLE_SIZE}}";
        const baseFontSize = parseFloat(baseFontSizeStr) || 40;
        const labelEl = root.querySelector('.ticker-vert-label');
        const leftPadding = labelEl && labelEl.style.display !== 'none' ? labelEl.offsetWidth : 0;

        const maxWidth = container.offsetWidth - leftPadding - 40;

        el.style.fontSize = baseFontSize + "px";

        let currentWidth = el.scrollWidth;
        if (currentWidth > maxWidth && currentWidth > 0) {
            const newSize = (maxWidth / currentWidth) * baseFontSize;
            el.style.fontSize = Math.min(newSize, baseFontSize) + "px";
        }
    }

    function runCycle() {
        if (!cycleRunning || !viewport) return;
        const el = document.createElement('div');
        el.className = 'ticker-vert-item';
        el.textContent = items[currentIndex];
        viewport.appendChild(el);

        adjustFontSize(el);

        void el.offsetWidth;
        el.classList.add('entering');

        cycleTimer = setTimeout(() => {
            if (!cycleRunning) { if (el.parentNode) el.parentNode.removeChild(el); return; }
            el.classList.remove('entering');
            el.classList.add('leaving');
            currentIndex = (currentIndex + 1) % items.length;
            setTimeout(() => {
                if (el.parentNode) el.parentNode.removeChild(el);
                if (cycleRunning) runCycle();
            }, 500);
        }, displayMs);
    }

    root.__slt_show = () => {
        cycleRunning = true;
        const tl = gsap.timeline();
        tl.to(container, { opacity: 1, y: 0, duration: 0.6, ease: "power2.out" });
        tl.add(() => { runCycle(); }, "+ =0.1");
        return tl;
    };

    root.__slt_hide = () => {
        cycleRunning = false;
        if (cycleTimer) clearTimeout(cycleTimer);
        viewport.querySelectorAll('.ticker-vert-item').forEach(i => i.parentNode && i.parentNode.removeChild(i));
        const tl = gsap.timeline();
        tl.to(container, { opacity: 0, y: 100, duration: 0.4, ease: "power2.in" });
        return tl;
    };

    window.addEventListener('resize', () => {
        viewport.querySelectorAll('.ticker-vert-item').forEach(el => adjustFontSize(el));
    });
})();
